#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

   float d = uTexSize.zw;
   vec3 deltax = (GetPixel(vUv + vec2(1,0)*d) + GetPixel(vUv + vec2(1,0)*d))*0.5;
   vec3 deltay = (GetPixel(vUv + vec2(0,1)*d) + GetPixel(vUv + vec2(0,1)*d))*0.5;


   ret = ((deltax+deltay - texture(sampler_main, (vUv-0.5) + 0.5 )));
//    ret = texture( sampler_main, vUv ).xyz;
//    ret = ret-0.001;// - q6;// - 0.08; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = 0.25 + 0.5*vUv; //MilkDrop2077 zoomed effect

vec2 uv2 = vUv;
if(uv2.x >= 0.5) {uv2.x = 1-uv2.x;}
if(uv2.y >= 0.5) {uv2.y = 1-uv2.y;}

vUv.x=uv2.x;
vUv.y=uv2.y;


vec3 base = GetBlur3(vUv) + GetBlur2(vUv) + GetBlur1(vUv) + texture(sampler_main, vUv)*1.0747 - 0.55 ;
a =base.x/10;b = base.y/8; c = base.x/3;
c = c + b + a-b;
a = a + c + a*c;
base = .3+c.x;
ret = base*(0.552-base)*(2-base)*2*vec3(1.2,2.3,.5) + pow(base,2)*vec3(2.6,-.6,0.8); //MilkDrop2077 color mod
//ret.xy = ret.yx;

ret *= vec3(vUv.x*3,-1,vUv.y*6);
//ret = ret*(1-ret+)*3; //MilkDrop2077 solarize effect


ret = mix(ret,vec3(1.5,2.5,2.6)-0.2,GetBlur2(vUv).y);
ret = mix(ret,vec3(.4,0.5,1.2)+1,GetPixel(vUv).y*.2);
ret -= 0.1;

//MilkDrop3 Brightness Mode:
ret *= 0.8;

  fragColor = ret;
}
